public int minMovesToConvert(String s) {
    int count = 0;
    for (int i = 0; i < s.length() - 2; i++) {
        if (s.charAt(i) == 'X' && s.charAt(i + 1) == 'X' && s.charAt(i + 2) == 'X') {
            count++;
            i += 2; // move by 3
        }
    }
    return count;
}
```

